async (page) => {
  // Rat is visible in upper right area of screen (~1075, 260)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 1075, y: 260 });
  await page.waitForTimeout(5000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return null;
    return {
      player_position: gs.player_position,
      player_stats: gs.player_stats,
      nearby_entities: gs.nearby_entities ? gs.nearby_entities.slice(0, 10) : [],
      nearest_mob: gs.nearest_mob,
      current_target: gs.current_target,
      inventory: gs.inventory
    };
  });
  return JSON.stringify(state);
}

