async (page) => {
  const TILE = 48, CX = 640, CY = 360;

  const getCoords = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return null;
    const TILE = 48, CX = 640, CY = 360;
    const px = gs.player_position.x, py = gs.player_position.y;
    // Find nearest rat only (safe to fight)
    const rat = (gs.nearby_entities||[]).filter(e=>e.type===3&&e.name==='Rat').sort((a,b)=>a.distance-b.distance)[0];
    return {
      px, py, hp: gs.player_stats.hp, maxHp: gs.player_stats.max_hp,
      rat: rat ? {sx: CX+(rat.x-px)*TILE, sy: CY+(rat.y-py)*TILE, dist: rat.distance} : null
    };
  });

  const click = (x, y) => page.evaluate(({x,y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX:x, clientY:y, bubbles:true}));
  }, {x, y});

  // Kill one rat to get some healing from passive regen
  const state = await getCoords();
  if (state && state.rat && state.rat.sx >= 0 && state.rat.sx <= 1280 && state.rat.sy >= 0 && state.rat.sy <= 720) {
    await click(state.rat.sx, state.rat.sy);
    await page.waitForTimeout(6000);
  }

  // Wait for HP regen
  await page.waitForTimeout(8000);

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? {pos: gs.player_position, hp: gs.player_stats.hp, maxHp: gs.player_stats.max_hp} : null;
  });

  return JSON.stringify(finalState);
}

