async (page) => {
  const click = (x, y) => page.evaluate(({x,y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX:x, clientY:y, bubbles:true}));
  }, {x, y});

  // Walk toward Blacksmith at (199,169) from (189,157) - 10E, 12S
  // Click southeast - x=1120, y=640 (as far south as possible)
  await click(1120, 640);
  await page.waitForTimeout(4000);

  let pos = await page.evaluate(() => window.__latestGameState?.player_position);

  // Fine-tune: check if close enough to click Blacksmith directly
  if (pos) {
    const dx = 199 - pos.x, dy = 169 - pos.y;
    const sx = 640 + dx*48, sy = 360 + dy*48;
    if (sx >= 0 && sx <= 1280 && sy >= 0 && sy <= 660) {
