  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const npcs = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs ? {pos: gs.player_position, npcs: (gs.nearby_entities||[]).filter(e=>e.type===1&&e.distance<=5)} : null;
  });
