async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    if (!gs) return null;
    const px = gs.player_position.x, py = gs.player_position.y;
    const mobs = (gs.nearby_entities||[]).filter(e=>e.type===3).slice(0,5).map(e=>({name:e.name,hp:e.hp,dist:e.distance,sx:640+(e.x-px)*48,sy:360+(e.y-py)*48}));
    const drops = (gs.nearby_entities||[]).filter(e=>e.type===4).slice(0,5).map(e=>({name:e.name,dist:e.distance,sx:640+(e.x-px)*48,sy:360+(e.y-py)*48}));
    // Also check type 12 (plants/objects) for clues
    const objects = (gs.nearby_entities||[]).filter(e=>e.type===12).slice(0,5).map(e=>({name:e.name,dist:e.distance,sx:640+(e.x-px)*48,sy:360+(e.y-py)*48}));
    return {pos:gs.player_position, hp:gs.player_stats?.hp, maxHp:gs.player_stats?.max_hp, level:gs.player_stats?.level, mobs, drops, objects, inv:gs.inventory};
  });

  const log = [];
  for (let i = 0; i < 10; i++) {
    const s = await getState();
    if (!s) break;

    if (s.hp < s.maxHp * 0.3) {
      log.push('DANGER - retreating');
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 500); });
      await page.waitForTimeout(3000);
      break;
    }

    // Pick up drops
    if (s.drops.length > 0 && s.drops[0].dist <= 4) {
      log.push(`PICKUP: ${s.drops[0].name}`);
      await click(s.drops[0].sx, s.drops[0].sy);
      await page.waitForTimeout(1000);
      continue;
    }

    const target = s.mobs.find(m=>!m.name) || s.mobs.find(m=>m.name==='Snek') || s.mobs.sort((a,b)=>a.dist-b.dist)[0];
    if (!target) {
      // Explore more of beach - walk east
      await click(1250, 360);
      await page.waitForTimeout(3000);
      continue;
    }

    log.push(`L${s.level} HP:${s.hp} ${target.name||'UNNAMED'}@${target.dist}`);
    await click(target.sx, target.sy);
    await page.waitForTimeout(target.dist > 5 ? 4000 : 8000);
  }

  const final = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({log, pos: final?.pos, hp: final?.hp, maxHp: final?.maxHp, level: final?.level, inv: final?.inv, drops: final?.drops, objects: final?.objects});
}

