async (page) => {
  // Try to use game API to navigate to Wife's location
  const result = await page.evaluate(() => {
    try {
      // Try different game APIs
      const player = window.game?.player;
      const map = window.game?.map;

      // Check if there's a teleport function
      const fns = [];
      if (player) fns.push(...Object.keys(player).filter(k => typeof player[k] === 'function').filter(k => k.match(/tele|warp|move|go|walk/i)));

      return { 
        playerFns: fns.slice(0, 20),
        gameFns: Object.keys(window.game || {}).filter(k => typeof window.game[k] === 'function').slice(0, 20)
      };
    } catch(e) { return {error: e.message}; }
  });
  return JSON.stringify(result);
}

