  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('after exit:', JSON.stringify(pos));

  // Now scan exterior map at x=195-225, y=215-225 for non-colliding tiles (potential tent entrances)
  const scanResult = await page.evaluate(() => {
    const map = window.game?.map;
    if (!map || !map.isColliding) return 'no map';

    const openTiles = [];
    for (let y = 213; y <= 225; y++) {
      for (let x = 192; x <= 230; x++) {
        if (!map.isColliding(x, y)) {
          openTiles.push({x, y});
        }
      }
    }
    return openTiles;
  });

  return JSON.stringify({pos, scan: scanResult});
}

