async (page) => {
  // Click through Sorcerer dialogue - multiple times
  const clickSorcerer = async () => {
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const pos = JSON.parse(state).player_position;
    const sx = 640 + (706 - pos.x)*48;
    const sy = 360 + (101 - pos.y)*48;
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x: sx, y: sy});
    await page.waitForTimeout(2000);
  };

  // Click 4 times to advance dialogue
  for (let i = 0; i < 4; i++) {
    await clickSorcerer();
    await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const pos = JSON.parse(state).player_position;
    // If we teleported out, stop
    if (pos.x < 500) break;
  }

  // Try quest button
  const questResult = await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) { btn.click(); return 'clicked quest-button'; }
    return 'no quest-button';
  });

  await page.waitForTimeout(1000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const quest = JSON.parse(state).quests.find(q => q.key === 'desertquest');
  const pos = JSON.parse(state).player_position;

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({pos, quest, questResult});
}

